func seedRecallResource(t *testing.T, db *sql.DB, rt, id, data string) {
	t.Helper()
	if _, err := db.Exec(`INSERT INTO resources (resource_type, id, data) VALUES (?, ?, ?)`, rt, id, data); err != nil {
		t.Fatalf("seed resource: %v", err)
	}
}

